const products = $input.first().json.products || [];

const results = products.map(p => {
  const title = p.title || '';
  const desc = p.body_html ? p.body_html.replace(/<[^>]+>/g, '') : '';
  const hasImages = p.images && p.images.length > 0;
  const hasVariants = p.variants && p.variants.length > 0;
  const hasPrice = p.variants && p.variants[0]?.price;
  const hasTags = p.tags && p.tags.length > 0;

  const issues = [];
  if (title.length < 20) issues.push('Título demasiado corto (<20 chars)');
  if (title.length > 70) issues.push('Título demasiado largo para IA (>70 chars)');
  if (desc.length < 100) issues.push('Descripción pobre (<100 chars)');
  if (!hasImages) issues.push('Sin imágenes');
  if (!hasTags) issues.push('Sin tags — los agentes no pueden categorizar');
  if (!hasPrice) issues.push('Sin precio visible');

  const score = Math.max(0, 100 - (issues.length * 20));

  return {
    id: p.id,
    title,
    score,
    issues,
    ready_for_agents: issues.length === 0
  };
});

const notReady = results.filter(p => !p.ready_for_agents);
const avgScore = results.reduce((a, b) => a + b.score, 0) / results.length;

return [{
  json: {
    total: results.length,
    ready: results.filter(p => p.ready_for_agents).length,
    not_ready: notReady.length,
    avg_score: Math.round(avgScore),
    top_issues: notReady.slice(0, 10).map(p => `• ${p.title}: ${p.issues.join(', ')}`).join('\n'),
    all_results: results
  }
}];

const data = $input.first().json;
const emoji = data.avg_score >= 80 ? '🟢' : data.avg_score >= 50 ? '🟡' : '🔴';

const msg = `${emoji} *AUDITORÍA AGENTIC COMMERCE*\n` +
  `Fecha: ${new Date().toLocaleDateString('es-ES')}\n\n` +
  `📦 Productos analizados: ${data.total}\n` +
  `✅ Listos para agentes IA: ${data.ready}\n` +
  `⚠️ Necesitan mejora: ${data.not_ready}\n` +
  `📊 Puntuación media: ${data.avg_score}/100\n\n` +
  `*TOP 10 PRODUCTOS A MEJORAR:*\n${data.top_issues}\n\n` +
  `👉 Mejora estos primero para aparecer en búsquedas de ChatGPT.`;

return [{ json: { message: msg } }];
